#include <unordered_set>
#include <vector>
#include <string>

class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        vector<string> result;
        unordered_set<string> seen;

        for (char c : s) {
            string substr = {c};
            if (seen.find(substr) != seen.end()) {
                result.push_back(substr);
            }
            seen.insert(substr);
        }

        return result;
    }
};
```

